messages.content:
CLUSTER:
[
 {
  "riskId": "risk.ledger-self-audit.serviceable-factor-conflation",
  "title": "The 0.55 serviceable factor conflates 'segments we'd like' with 'compliance-cleared demand' — the corpus puts the reachable slice below the band's floor",
  "narrative": "serviceableFactor 0.55 is the model's only pure assumption leaf on the SAM path, justified by three EU cert regimes cited qualitatively. The corpus disagrees in two directions at once: every quantified B2B analogue found puts SAM far below 45–65% of TAM (worked examples near 12%), and the search surfaced a materially larger regulatory stack than the node cites — WEEE, RoHS, EORI customs registration, the 2024/1364 DC rating scheme, and EED 2024/1791 KPI/waste-heat disclosure. Each omitted instrument is a compliance artifact with lead time that gates tender prequalification. For a pre-launch entrant in its first 12 months, the demand that is actually open to bid is not 55% of TAM; it is the fraction whose tenders it can prequalify for before certifications complete — plausibly below 0.40, under the band's floor for a reason the band never encoded.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "The 0.55 is unanchored: the only quantified analogues in the corpus are SAM examples near 12% of TAM and SOM benchmarks of 1–10%, all far below the 0.45–0.65 band; simultaneously the cited cert basis (EN 50600, 2019/424, CE/TÜV) omits WEEE, RoHS, EORI, 2024/1364, and EED 2024/1791",
    "refs": [
     "digest:serviceable-benchmark#c11",
     "digest:serviceable-benchmark#c13",
     "digest:serviceable-benchmark#c8",
     "digest:serviceable-benchmark#c9",
     "ledger:serviceableFactor"
    ]
   },
   {
    "step": "propagation",
    "text": "Each omitted instrument lands as a procurement gate: EED KPI and waste-heat disclosure obligations and the 2024/1364 rating scheme flow into operator tender prequalification, so demand from compliance-sensitive large operators (the venture's declared first channel) is closed to an entrant mid-certification during exactly its first 12 months",
    "refs": [
     "digest:serviceable-benchmark#c9",
     "digest:serviceable-benchmark#c10",
     "profile:Stage",
     "profile:Who is the primary buyer you'll sell through first?"
    ]
   },
   {
    "step": "model-impact",
    "text": "The serviceable share of TAM for the Year-1 window sits below the 0.45 floor; SAM contracts beyond anything the tornado shows, and YAM contracts with it even at the curated 3% obtainable rate",
    "refs": [
     "ledger:serviceableFactor",
     "ledger:obtainableFactor"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "Certification and disclosure requirements appearing in CE operator PDU/rack-power tender prequalification lists",
    "where": "Frankfurt/Amsterdam/Warsaw colocation procurement packages; hyperscaler supplier-onboarding portals",
    "threshold": "EED 2024/1791 KPI or 2024/1364 rating-scheme references in ≥2 of first 5 target-account tenders",
    "updates": "increases"
   },
   {
    "signal": "Implementation timeline and scope of the EU DC rating scheme and EED delegated acts",
    "where": "EUR-Lex / European Commission energy-efficiency dockets for Directive 2024/1791 and Delegated Regulation 2024/1364",
    "threshold": "Supplier-facing obligations confirmed to apply at equipment-procurement level within 12 months",
    "updates": "increases"
   },
   {
    "signal": "Own certification program milestones vs plan (CE, TÜV, RoHS/WEEE registration, EORI)",
    "where": "Internal cert tracker vs notified-body lead-time quotes",
    "threshold": "Any critical cert slipping past month 6 of the launch window",
    "updates": "increases"
   }
  ],
  "judgeTotal": 17,
  "distinctByJudge": "This is not a bare band-edge claim: the whyMissable field names a NEW definitional failure ('segments we intend to serve' vs 'tenders we can prequalify for in Year 1') plus a regulatory stack the node's own citations omit. Docked one point because the 'B2B SAM analogues sit near 12%' half of the argument is a generic benchmark a diligent founder might raise."
 },
 {
  "riskId": "risk.regulatory-gauntlet.eichrecht-metering-foreclosure",
  "title": "German legal metrology (MessEG/MessEV) forecloses billing-grade outlet metering — the intelligent PDU's core value proposition — in the model's largest geography",
  "narrative": "Half of this funnel is Germany, and the product's premium is 'intelligent' — per-outlet metering. But in Germany, any meter whose output becomes an invoice line (colo tenant power billing, chargeback) must be conformity-assessed under the Mess- und Eichgesetz — a legal-metrology regime entirely separate from CE/LVD/TÜV product safety. Incumbents ship Eichrecht/MID-certified metering options; a new entrant without type examination cannot lawfully anchor billing, demoting its metering to 'indicative only' and stripping the differentiation exactly where the model concentrates its weight. The certification path runs 12–18 months — past the YAM window. EED 2024/1791's KPI-disclosure regime is simultaneously institutionalizing measured energy data, making certified metering more, not less, decisive.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "German colo operators billing tenants on measured kWh must use legally-verified meters under MessEG/MessEV; PDU-embedded outlet metering without PTB-recognized type examination cannot serve as the billing basis in the market carrying ~1,955 MW of installed IT power",
    "refs": [
     "profile:Product",
     "digest:geo-DE#c13"
    ]
   },
   {
    "step": "propagation",
    "text": "geo.DE carries 0.50 of the funnel, and EED 2024/1791 KPI/energy-disclosure duties are pushing operators toward invoice-grade measured power; competitors with certified metering SKUs win the metered-billing use case, relegating the entrant to non-billing deployments in DE colocation",
    "refs": [
     "ledger:geo.DE",
     "digest:serviceable-benchmark#c9",
     "ledger:seg.colocation"
    ]
   },
   {
    "step": "model-impact",
    "text": "The reachable share of the German half of the funnel is overstated: billing-grade metered deployments are foreclosed until a ~12–18-month legal-metrology certification completes, i.e. after the Year-1 window closes — a reach haircut the 0.55 serviceableFactor never priced",
    "refs": [
     "ledger:serviceableFactor",
     "ledger:obtainableFactor"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "'Eichrechtskonform'/MID-certified metering requirements appearing in DE colo fit-out RFQs",
    "where": "TED notices; Frankfurt/Berlin colocation fit-out RFQs and operator technical specifications",
    "threshold": "metering-certification clauses in ≥2 DE colo tenders",
    "updates": "increases"
   },
   {
    "signal": "Incumbent PDU vendors marketing legally-certified metering options",
    "where": "Bachmann, Rittal, Legrand/Raritan German price lists and datasheets",
    "threshold": "≥2 major vendors adding MID/Eichrecht-certified metering SKUs",
    "updates": "increases"
   }
  ],
  "judgeTotal": 17,
  "distinctByJudge": "The whyMissable field makes a credible case: the compliance sweep covers product safety and energy law (LVD, EMC, EN 50600), while legal metrology only bites when meter output becomes an invoice line — a different legal family entirely. Docked one point because MID/Eichrecht billing requirements are well-known in adjacent German markets (EV charging), so a founder selling metered hardware into DE has some chance of stumbling on it."
 },
 {
  "riskId": "risk.execution-window.serviceable-reach-is-flow-not-stock",
  "title": "serviceableFactor 0.55 is a stock; a pre-launch entrant only owns a flow — Year-1 reach is realistically two countries, one channel",
  "narrative": "The 0.55 serviceable share treats channel and regulatory reach as an endowment. But reach is BUILT during the same 12 months it is supposed to be harvested: distributor contracts signed, country registrations obtained, support commitments staffed, five languages covered. The only quantified external analogues the research found for a realistically serviceable slice are 12% (Scalarly's regional-narrowing example) and single-digit SOM ranges — nothing supports 45–65% for a pre-launch vendor. Concretely: Switzerland (8% of TAM) is non-EU and needs its own conformity path; Poland and 'Other CE' need local-language channel that doesn't exist yet; even in Germany, coverage means signed distributors, not the country's existence. A pre-launch Year-1 footprint of DE plus NL through one distributor is closer to 0.30–0.35 of TAM than 0.55.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "The 0.55 is an unanchored assumption leaf: every external quantified analogue found sits far lower (12% regional-narrowing example; investor preference for bottom-up over top-down reach claims), and no bottom-up channel-coverage model exists in the ledger",
    "refs": [
     "digest:serviceable-benchmark#c3",
     "digest:serviceable-benchmark#c13",
     "ledger:serviceableFactor"
    ]
   },
   {
    "step": "propagation",
    "text": "Reach must be constructed country-by-country inside the Year-1 window: SAM is a capability statement (compliance, integrations, support model, channel) and each element is unbuilt at launch; non-EU Switzerland (8% of the geo split) and the CEE tail require separate conformity and channel work",
    "refs": [
     "digest:serviceable-benchmark#c12",
     "digest:serviceable-benchmark#c10",
     "ledger:geo.CH",
     "ledger:geo.other"
    ]
   },
   {
    "step": "model-impact",
    "text": "Year-1 serviceable share falls from 0.55 toward a two-country, one-channel footprint; SAM contracts proportionally and YAM with it, even if the obtainable percentage of that SAM holds",
    "refs": [
     "ledger:serviceableFactor",
     "ledger:geo.DE"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "Count and geographic coverage of signed CE distribution agreements at launch",
    "where": "Vendor's own channel announcements cross-checked against Rexel/Sonepar and regional CE distributor line cards",
    "threshold": "<2 countries covered by signed agreements at launch",
    "updates": "increases"
   },
   {
    "signal": "Swiss conformity path status for the product (non-EU, post-MRA friction for networked electrical equipment)",
    "where": "Swiss authorized-representative and conformity guidance (SECO / Swissmem publications) plus the vendor's own compliance roadmap",
    "threshold": "No Swiss authorized rep appointed by launch",
    "updates": "increases"
   }
  ],
  "judgeTotal": 16,
  "distinctByJudge": "This is not 'band edge could be true' — the whyMissable names a NEW structural reason: the 0.45–0.65 band brackets steady state while the funnel's missing time axis hides that Year-1 reach starts near zero and ramps. Docked one point because 'SOM is capacity-built, not a SAM fraction' is a fairly standard sizing critique a diligent founder might independently raise."
 },
 {
  "riskId": "risk.base-rate-analogy.regulatory-stack-undercounted-serviceable",
  "title": "The serviceable haircut is priced against a 2019-era 3-item cert list while the binding 2024 stack is materially larger",
  "narrative": "serviceableFactor 0.55 is justified by three regimes: EN 50600, ecodesign 2019/424, CE/TÜV. The corpus surfaces a larger and newer stack — WEEE, RoHS, FCC, EORI customs registration, the EU Delegated Regulation 2024/1364 data-centre rating scheme, and the Energy Efficiency Directive 2024/1791's KPI and waste-heat-reuse disclosure duties on operators. Each missing artifact removes a buyer class from the entrant's reachable set: operators under EED reporting increasingly demand component-level efficiency documentation at procurement, and distributors will not list a product without WEEE/RoHS registration in each country. The regulatory-reach basis for the haircut is therefore stronger than the ledger represents, pushing the factor toward or below its 0.45 band edge — a level the band treats as a tail, not a central case.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "EU Delegated Regulation 2024/1364 (rating scheme, effective May 2024) and EED 2024/1791 (KPI/WHR disclosure) land compliance duties on CE data-centre operators in 2024–26, pulling component-level energy documentation into procurement questionnaires",
    "refs": [
     "digest:serviceable-benchmark#c8",
     "digest:serviceable-benchmark#c9"
    ]
   },
   {
    "step": "propagation",
    "text": "The entrant must clear WEEE, RoHS, CE/TÜV, EORI and provide EN 50600-aligned and ecodesign documentation per country; every artifact not held at launch removes the corresponding buyer class or geography from the serviceable set — a larger haircut than the 3-regime basis the node cites",
    "refs": [
     "digest:serviceable-benchmark#c10",
     "digest:serviceable-benchmark#c7",
     "ledger:serviceableFactor"
    ]
   },
   {
    "step": "model-impact",
    "text": "The 0.55 centering reflects an undercounted barrier; the fuller stack pushes the serviceable share to or below the 0.45 band edge, and SAM definitions in the corpus explicitly include compliance/procurement reach as a gating dimension",
    "refs": [
     "ledger:serviceableFactor",
     "digest:serviceable-benchmark#c12",
     "digest:serviceable-benchmark#c13"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "Component-level efficiency and sustainability documentation appearing as mandatory annexes in CE colo/enterprise RFQs",
    "where": "DE/NL data-centre fit-out RFQs and operator supplier-qualification questionnaires",
    "threshold": "≥2 RFQs in the first two quarters listing EED-KPI or 2024/1364-aligned documentation as a mandatory annex",
    "updates": "increases"
   },
   {
    "signal": "National enforcement cadence of EED transposition on data-centre operators",
    "where": "German EnEfG data-centre reporting portal and BMWK implementation guidance releases",
    "threshold": "First enforcement/reporting deadline enforced on operators ≤ Year-1 window",
    "updates": "increases"
   }
  ],
  "judgeTotal": 17,
  "distinctByJudge": "The headline conclusion is 'factor at/below its own band edge', which the client has seen — but the risk supplies a genuinely new reason: the haircut's basis is a 2019-vintage 3-item list, and the binding 2024 instruments postdate the derivation, which the whyMissable explicitly identifies as the box-looks-ticked trap. Not a 4 because a founder tracking EU data-centre regulation would plausibly have 2024/1364 and EED on a watchlist."
 },
 {
  "riskId": "risk.competitive-foreclosure.legrand-dual-brand-intelligent-pdu-lock",
  "title": "Legrand's dual ownership of Raritan and Server Technology makes the intelligent-PDU sub-market far more closed than the 0.55 whole-market CR3 suggests",
  "narrative": "The ledger's CR3 of 0.55 is extrapolated from whole-PDU-market data and even the digest treats Raritan and Server Technology as separate 'top players' — but both belong to Legrand. In the intelligent-PDU sub-market where this venture actually plays, one owner controls the two pioneering brands whose outlet-level monitoring APIs are wired into operators' DCIM and monitoring stacks, alongside Vertiv (Geist) and Schneider with their own DCIM suites. That changes the nature of the serviceable market: the enterprise (29%) and colocation (18%) replacement sockets that a Year-1 entrant must live off are not vendor-neutral — swapping the PDU means re-integrating the monitoring layer, so incumbents win renewals without a selection event. The 0.55 serviceable factor treats regulatory reach as the only haircut; the software-integration lock quietly removes another tranche of TAM from anyone's reach but the incumbents'.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "The CR3 estimate rests on whole-PDU data and a single 15.8% Schneider datapoint, while Credence lists Server Technology and Raritan as separate top players — masking that Legrand owns both intelligent-PDU pioneer brands, so intelligent-PDU concentration is materially higher than the whole-market 0.55 proxy",
    "refs": [
     "digest:cr3-vendors#c5",
     "digest:cr3-vendors#c0",
     "ledger:shape.cr3"
    ]
   },
   {
    "step": "propagation",
    "text": "Intelligent PDUs are purchased as endpoints of DCIM/monitoring stacks; installed bases in the enterprise and colocation segments — the venture's realistic Year-1 sockets — are standardized on incumbent APIs and management suites, so replacement demand renews with the incumbent without a competitive evaluation",
    "refs": [
     "ledger:seg.enterprise",
     "ledger:seg.colocation",
     "profile:Product"
    ]
   },
   {
    "step": "model-impact",
    "text": "The serviceable haircut (0.55) was justified only by the EU certification stack and carries no integration-lock component; adding the DCIM-locked share of replacement demand pushes the truly serviceable fraction below the model's 0.45 low edge",
    "refs": [
     "ledger:serviceableFactor",
     "digest:cr3-vendors#c1"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "Integration requirements in CE retrofit/replacement RFQs (incumbent-compatible APIs or named DCIM suites specified as mandatory)",
    "where": "CE colocation and enterprise retrofit tender documents; DCIM vendor compatibility matrices",
    "threshold": "≥50% of retrofit RFQs specify compatibility with an incumbent's management ecosystem as a hard requirement",
    "updates": "increases"
   },
   {
    "signal": "Legrand commentary on Raritan + Server Technology portfolio consolidation and cross-sell/renewal rates in the data-center segment",
    "where": "Legrand capital-markets day and quarterly earnings calls, data-center division commentary",
    "threshold": "Explicit claims of installed-base renewal advantage or unified intelligent-PDU platform strategy",
    "updates": "increases"
   }
  ],
  "judgeTotal": 16,
  "distinctByJudge": "The whyMissable case is genuine: the digest lists Raritan and Server Technology as separate top players and serviceableFactor was framed purely as a regulatory haircut, so the integration-lock tranche was never on the list. Docked one point because Legrand's 2015/2017 acquisitions are widely known in the data-center power industry, so a domain-fluent founder plausibly has this."
 },
 {
  "riskId": "risk.regulatory-gauntlet.per-country-access-stack",
  "title": "The unmodeled per-country access stack — stiftung EAR WEEE numbers, packaging EPR, EORI, Swiss non-EU paperwork — serializes CE entry against a 12-month clock",
  "narrative": "The serviceableFactor derivation admits its cert stack 'justifies <1.0 but doesn't quantify 0.55' and names only three regimes. The corpus itself surfaces a larger stack: WEEE registration (per-country, per-brand — Germany's stiftung EAR alone runs 2–4 months), packaging EPR (VerpackG/LUCID), EORI customs setup, RoHS/REACH documentation — and Switzerland sits outside the EU single market entirely, requiring separate importer and recycling (SENS) arrangements. None of these is individually a 'market risk'; the mechanism is serialization: each country becomes lawfully sellable only after its registrations complete, so within a 12-month window several geographies are unreachable for part or all of the year. That pushes effective Year-1 reach below the band's own low edge, and plausibly removes Switzerland (0.08 of the funnel) from the first-year set altogether.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "First sale in each CE country requires completed country-level registrations: DE WEEE via stiftung EAR (ElektroG), packaging EPR (LUCID), EORI, plus non-EU Switzerland's separate importer/recycling regime — a stack the corpus documents as materially broader than the three regimes the model cites",
    "refs": [
     "digest:serviceable-benchmark#c10",
     "ledger:geo.CH"
    ]
   },
   {
    "step": "propagation",
    "text": "The digest's own tension flags that the fuller stack pushes serviceableFactor toward or below 0.45; but the deeper effect is temporal — registrations serialize country launches, so a pre-launch entrant's lawfully-reachable geography expands stepwise across the very 12 months the YAM measures",
    "refs": [
     "ledger:serviceableFactor",
     "digest:serviceable-benchmark#c12",
     "profile:Stage"
    ]
   },
   {
    "step": "model-impact",
    "text": "Year-1 serviceable reach sits below the 0.45 band edge, and the Swiss slice — with its distinct non-EU paperwork and self-operation-heavy buyer base — falls out of the first-year reachable scope entirely",
    "refs": [
     "ledger:serviceableFactor",
     "ledger:geo.CH"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "stiftung EAR registration processing times and backlog",
    "where": "stiftung EAR portal and published registration statistics",
    "threshold": "processing exceeding 3 months for new B2B registrants",
    "updates": "increases"
   },
   {
    "signal": "Whether incumbents maintain distinct Swiss-compliance SKUs and importer structures",
    "where": "Bachmann/Rittal/Vertiv Swiss price lists and Swiss distributor catalogues",
    "threshold": "separate CH SKUs/importer-of-record arrangements visible at ≥2 incumbents",
    "updates": "increases"
   }
  ],
  "judgeTotal": 17,
  "distinctByJudge": "The digest's own tension flag (c12) already pushes serviceableFactor toward 0.45, so the band-edge portion is partly in-model; the genuinely additive insight is the serialization-against-clock mechanism and the CH exclude, which per whyMissable only surfaces when a compliance Gantt is built against the sales plan. Novel dynamic, but built on a tension the ledger already surfaces."
 }
]

